    public Object parseOrder(Object order, Object... optionalArgs)
    {
        //
        // createOrder, cancelOrder
        //
        //     {
        //         "order_id": "6540219377766741832",
        //         "client_oid": "CCXT_d6ef7c3db6c1495aa8b757"
        //     }
        //
        // fetchOpenOrders, fetchOrder, fetchOrders
        //
        //     {
        //         "account_id": "ce075bef-1234-4321-bd6g-ff9007252e63",
        //         "order_id": "6530219477767564494",
        //         "client_oid": "CCXT_7ce730f0388441df9bc218",
        //         "order_type": "LIMIT",
        //         "time_in_force": "GOOD_TILL_CANCEL",
        //         "side": "BUY",
        //         "exec_inst": [ ],
        //         "quantity": "0.00020",
        //         "limit_price": "20000.00",
        //         "order_value": "4",
        //         "avg_price": "0",
        //         "trigger_price": "0",
        //         "ref_price": "0",
        //         "cumulative_quantity": "0",
        //         "cumulative_value": "0",
        //         "cumulative_fee": "0",
        //         "status": "ACTIVE",
        //         "update_user_id": "ce075bef-1234-4321-bd6g-gg9007252e63",
        //         "order_date": "2023-06-15",
        //         "instrument_name": "BTC_USD",
        //         "fee_instrument_name": "BTC",
        //         "create_time": 1686806053992,
        //         "create_time_ns": "1686806053992921880",
        //         "update_time": 1686806053993
        //     }
        //
        // createOrders
        //     {
        //             "code" : 306,
        //             "index" : 1,
        //             "client_oid" : "1698068111133_1",
        //             "message" : "INSUFFICIENT_AVAILABLE_BALANCE",
        //             "order_id" : "6142909896519488207"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object code = this.safeInteger(order, "code");
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(code, null))) && Helpers.isTrue((!Helpers.isEqual(code, 0)))))
        {
            return this.safeOrder(new java.util.HashMap<String, Object>() {{
                put( "id", CryptocomCore.this.safeString(order, "order_id") );
                put( "clientOrderId", CryptocomCore.this.safeString(order, "client_oid") );
                put( "info", order );
                put( "status", "rejected" );
            }});
        }
        Object created = this.safeInteger(order, "create_time");
        Object marketId = this.safeString(order, "instrument_name");
        Object symbol = this.safeSymbol(marketId, market);
        Object execInst = this.safeValue(order, "exec_inst");
        Object postOnly = null;
        if (Helpers.isTrue(!Helpers.isEqual(execInst, null)))
        {
            postOnly = false;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(execInst)); i++)
            {
                Object inst = Helpers.GetValue(execInst, i);
                if (Helpers.isTrue(Helpers.isEqual(inst, "POST_ONLY")))
                {
                    postOnly = true;
                    break;
                }
            }
        }
        Object feeCurrency = this.safeString(order, "fee_instrument_name");
        final Object finalPostOnly = postOnly;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", CryptocomCore.this.safeString(order, "order_id") );
            put( "clientOrderId", CryptocomCore.this.safeString(order, "client_oid") );
            put( "timestamp", created );
            put( "datetime", CryptocomCore.this.iso8601(created) );
            put( "lastTradeTimestamp", CryptocomCore.this.safeInteger(order, "update_time") );
            put( "status", CryptocomCore.this.parseOrderStatus(CryptocomCore.this.safeString(order, "status")) );
            put( "symbol", symbol );
            put( "type", CryptocomCore.this.safeStringLower(order, "order_type") );
            put( "timeInForce", CryptocomCore.this.parseTimeInForce(CryptocomCore.this.safeString(order, "time_in_force")) );
            put( "postOnly", finalPostOnly );
            put( "side", CryptocomCore.this.safeStringLower(order, "side") );
            put( "price", CryptocomCore.this.safeNumber(order, "limit_price") );
            put( "amount", CryptocomCore.this.safeNumber(order, "quantity") );
            put( "filled", CryptocomCore.this.safeNumber(order, "cumulative_quantity") );
            put( "remaining", null );
            put( "average", CryptocomCore.this.safeNumber(order, "avg_price") );
            put( "cost", CryptocomCore.this.safeNumber(order, "cumulative_value") );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", CryptocomCore.this.safeCurrencyCode(feeCurrency) );
                put( "cost", CryptocomCore.this.safeNumber(order, "cumulative_fee") );
            }} );
            put( "trades", new java.util.ArrayList<Object>(java.util.Arrays.asList()) );
        }}, market);
    }

