    public Object parseLedgerEntry(Object item, Object... optionalArgs)
    {
        //
        //     {
        //         "account_id": "ce075cef-1234-4321-bd6e-gf9007351e64",
        //         "event_date": "2023-06-15",
        //         "journal_type": "TRADING",
        //         "journal_id": "6530219460124075091",
        //         "transaction_qty": "6.0091224",
        //         "transaction_cost": "6.0091224",
        //         "realized_pnl": "0",
        //         "order_id": "6530219477766741833",
        //         "trade_id": "6530219495775954765",
        //         "trade_match_id": "4611686018455865176",
        //         "event_timestamp_ms": 1686804665013,
        //         "event_timestamp_ns": "1686804665013642422",
        //         "client_oid": "CCXT_d6ea7c5db6c1495aa8b758",
        //         "taker_side": "",
        //         "side": "BUY",
        //         "instrument_name": "USD"
        //     }
        //
        Object currency = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(item, "event_timestamp_ms");
        Object currencyId = this.safeString(item, "instrument_name");
        Object code = this.safeCurrencyCode(currencyId, currency);
        currency = this.safeCurrency(currencyId, currency);
        Object amount = this.safeString(item, "transaction_qty");
        Object direction = null;
        if (Helpers.isTrue(Precise.stringLt(amount, "0")))
        {
            direction = "out";
            amount = Precise.stringAbs(amount);
        } else
        {
            direction = "in";
        }
        final Object finalDirection = direction;
        final Object finalAmount = amount;
        return this.safeLedgerEntry(new java.util.HashMap<String, Object>() {{
            put( "info", item );
            put( "id", CryptocomCore.this.safeString(item, "order_id") );
            put( "direction", finalDirection );
            put( "account", CryptocomCore.this.safeString(item, "account_id") );
            put( "referenceId", CryptocomCore.this.safeString(item, "trade_id") );
            put( "referenceAccount", CryptocomCore.this.safeString(item, "trade_match_id") );
            put( "type", CryptocomCore.this.parseLedgerEntryType(CryptocomCore.this.safeString(item, "journal_type")) );
            put( "currency", code );
            put( "amount", CryptocomCore.this.parseNumber(finalAmount) );
            put( "timestamp", timestamp );
            put( "datetime", CryptocomCore.this.iso8601(timestamp) );
            put( "before", null );
            put( "after", null );
            put( "status", null );
            put( "fee", new java.util.HashMap<String, Object>() {{
                put( "currency", null );
                put( "cost", null );
            }} );
        }}, currency);
    }

