    public Object parseTradingFees(Object response)
    {
        //
        // {
        //         "spot_tier": "3",
        //         "deriv_tier": "3",
        //         "effective_spot_maker_rate_bps": "6.5",
        //         "effective_spot_taker_rate_bps": "6.9",
        //         "effective_deriv_maker_rate_bps": "1.1",
        //         "effective_deriv_taker_rate_bps": "3"
        //  }
        //
        Object result = new java.util.HashMap<String, Object>() {{}};
        Helpers.addElementToObject(result, "info", response);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(((Object)this.symbols))); i++)
        {
            Object symbol = Helpers.GetValue(((Object)this.symbols), i);
            Object market = this.market(symbol);
            Object isSwap = Helpers.GetValue(market, "swap");
            Object takerFeeKey = ((Helpers.isTrue(isSwap))) ? "effective_deriv_taker_rate_bps" : "effective_spot_taker_rate_bps";
            Object makerFeeKey = ((Helpers.isTrue(isSwap))) ? "effective_deriv_maker_rate_bps" : "effective_spot_maker_rate_bps";
            Object tradingFee = new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "symbol", symbol );
                put( "maker", CryptocomCore.this.parseNumber(Precise.stringDiv(CryptocomCore.this.safeString(response, makerFeeKey), "10000")) );
                put( "taker", CryptocomCore.this.parseNumber(Precise.stringDiv(CryptocomCore.this.safeString(response, takerFeeKey), "10000")) );
                put( "percentage", null );
                put( "tierBased", null );
            }};
            Helpers.addElementToObject(result, symbol, tradingFee);
        }
        return result;
    }

    public Object parseTradingFee(Object fee, Object... optionalArgs)
    {
        //
        // {
        //      "instrument_name": "BTC_USD",
        //      "effective_maker_rate_bps": "6.5",
        //      "effective_taker_rate_bps": "6.9"
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString(fee, "instrument_name");
        Object symbol = this.safeSymbol(marketId, market);
        return new java.util.HashMap<String, Object>() {{
            put( "info", fee );
            put( "symbol", symbol );
            put( "maker", CryptocomCore.this.parseNumber(Precise.stringDiv(CryptocomCore.this.safeString(fee, "effective_maker_rate_bps"), "10000")) );
            put( "taker", CryptocomCore.this.parseNumber(Precise.stringDiv(CryptocomCore.this.safeString(fee, "effective_taker_rate_bps"), "10000")) );
            put( "percentage", null );
            put( "tierBased", null );
        }};
    }

    public Object sign(Object path, Object... optionalArgs)
    {
        Object api = Helpers.getArg(optionalArgs, 0, "public");
        Object method = Helpers.getArg(optionalArgs, 1, "GET");
        Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
        Object headers = Helpers.getArg(optionalArgs, 3, null);
        Object body = Helpers.getArg(optionalArgs, 4, null);
        Object type = this.safeString(api, 0);
        Object access = this.safeString(api, 1);
        Object url = Helpers.add(Helpers.add(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), ((String)type)), "/"), path);
        Object query = this.omit(parameters, this.extractParams(path));
        if (Helpers.isTrue(Helpers.isEqual(access, "public")))
        {
            if (Helpers.isTrue(Helpers.getArrayLength(Helpers.objectKeys(query))))
            {
                url = Helpers.add(url, Helpers.add("?", this.urlencode(query)));
            }
        } else
        {
            this.checkRequiredCredentials();
            Object nonce = String.valueOf(this.nonce());
            Object requestParams = this.extend(new java.util.HashMap<String, Object>() {{}}, parameters);
            Object paramsKeys = Helpers.objectKeys(requestParams);
            Object strSortKey = this.paramsToString(requestParams, 0);
            Object payload = Helpers.add(Helpers.add(Helpers.add(Helpers.add(path, nonce), this.apiKey), strSortKey), nonce);
            Object signature = this.hmac(this.encode(payload), this.encode(this.secret), sha256());
            Object paramsKeysLength = Helpers.getArrayLength(paramsKeys);
            final Object finalPath = path;
            body = this.json(new java.util.HashMap<String, Object>() {{
                put( "id", nonce );
                put( "method", finalPath );
                put( "params", parameters );
                put( "api_key", CryptocomCore.this.apiKey );
                put( "sig", signature );
                put( "nonce", nonce );
            }});
            // fix issue https://github.com/ccxt/ccxt/issues/11179
            // php always encodes dictionaries as arrays
            // if an array is empty, php will put it in square brackets
            // python and js will put it in curly brackets
            // the code below checks and replaces those brackets in empty requests
            if (Helpers.isTrue(Helpers.isEqual(paramsKeysLength, 0)))
            {
                Object paramsString = "{}";
                Object arrayString = "[]";
                body = Helpers.replace((String)body, (String)arrayString, (String)paramsString);
            }
            headers = new java.util.HashMap<String, Object>() {{
                put( "Content-Type", "application/json" );
            }};
        }
        final Object finalUrl = url;
        final Object finalBody = body;
        final Object finalHeaders = headers;
        return new java.util.HashMap<String, Object>() {{
            put( "url", finalUrl );
            put( "method", method );
            put( "body", finalBody );
            put( "headers", finalHeaders );
        }};
    }

    public Object handleErrors(Object code, Object reason, Object url, Object method, Object headers, Object body, Object response, Object requestHeaders, Object requestBody)
    {
        Object errorCode = this.safeString(response, "code");
        if (Helpers.isTrue(!Helpers.isEqual(errorCode, "0")))
        {
            Object feedback = Helpers.add(Helpers.add(this.id, " "), body);
            this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), errorCode, feedback);
            throw new ExchangeError((String)Helpers.add(Helpers.add(this.id, " "), body)) ;
        }
        return null;
    }
